b3=A.ce(ab1,b5,s2,"INDICATED (Widespread denervation)",A.a([A.t(!0,f0,j8,h2,f0,h3,g9,h0,f0,h4,h1,f0),A.t(!0,f0,j8,j8,f0,h3,h5,h6,f0,h4,h1,f0),A.t(!0,f0,j8,h2,f0,h3,h8,h9,f0,h4,i0,f0),A.t(!0,f0,q5,f0,f0,f0,"Tongue",f0,f0,f0,f0,f0),A.t(!0,f0,j8,q5,f0,f0,m7,m8,f0,f0,m9,f0),A.t(!0,f0,h2,j8,f0,f0,l5,l6,f0,f0,l7,f0),A.t(!0,f0,h2,j8,f0,f0,m0,l6,f0,f0,m1,f0),A.t(!0,f0,h2,j8,f0,f0,"Thoracic Paraspinals (T10)",f0,f0,f0,f0,f0)],n),"This patient demonstrates the Awaji/El Escorial criteria for ALS: both Upper Motor Neuron (UMN) signs (brisk reflexes, Babinski) and Lower Motor Neuron (LMN) signs (atrophy, fasciculations) across 3-4 body regions (Bulbar, Cervical, Thoracic, Lumbosacral). Normal SNAPs confirm the lesion is pre-ganglionic.",b4,"als",b6,ae7,ae6,!0,b3,A.a(["ALS requires evidence of both UMN and LMN involvement to make a clinical diagnosis.","Electrodiagnostically, look for 'active' denervation (Fibs/PSWs) and 'chronic' reinnervation (Large MUAPs) in at least 3 of 4 regions (Bulbar, Cervical, Thoracic, Lumbosacral).","Sensory NCS are characteristically normal in ALS; if abnormal, consider an alternative or co-morbid diagnosis."],af2),"Progressive Weakness with Muscle Twitching")
ae6=A.cd(28,"Weakness starting in feet and legs, moving upwards, and tingling in hands",d5,"Develop weakness in both legs over the past 3 days. Now having trouble walking and climbing stairs. Tingling in fingertips and toes. Had a severe 'stomach flu' (diarrhea) 2 weeks ago.",i4,"Sales",i4)
ae7=A.ch("Normal muscle bulk (it's too early for atrophy).",x6,"0 (Absent) throughout (at all levels).",x6,"Mildly decreased vibration at toes; otherwise normal.","Unsteady gait, requiring assistance to stand.","Bilateral Hip Flexion 3/5, Dorsiflexion 4/5. Grip strength 4/5. Sparing of cranial nerves so far.")
b6=A.a([A.V(ab4,d9),A.V(ab5,"CIDP is a chronic condition (symptoms >8 weeks); here the onset is acute (3 days)."),A.V("Transverse Myelitis","Transverse myelitis would usually present with an UMN pattern (eventually), a discrete sensory level on the trunk, and early bowel/bladder dysfunction; here reflexes are absent (LMN) and there is no sensory level."),A.V(aa7,"MG causes fluctuating weakness and usually involves cranial nerves (ptosis/diplopia) early on; it would NOT cause areflexia or sensory symptoms (tingling)."),A.V("Tick Paralysis","A classic mimic of GBS; would be ruled out by a thorough skin exam for a tick; clinically identical but usually lacks the CSF findings seen here.")],ae8)
b4=A.a7(["constitutional","No fever currently. Had severe diarrhea 2 weeks ago.","respiratory","Mild shortness of breath when lying flat. No cough.","neurological","Ascending weakness starting in feet. Tingling in hands and feet. Normal bowel and bladder control currently.","cardiovascular","Occasional racing heart (potential autonomic instability)."],af0,af0)
