c1=A.a([A.al(!1,"11.5",f0,g6,w9,p2),A.al(!0,f8,"63% Conduction Block at Forearm",u7,x0,n7),A.al(!1,g2,f0,i6,ac4,p2),A.al(!1,"13.5",f0,aa2,ac5,j5)],o)
